/**
 * OpenAI Node - Version 1.8
 * Discriminator: resource=file, operation=list
 */


interface Credentials {
  openAiApi: CredentialReference;
}

/** List assistants in the organization */
export type LcOpenAiV18FileListParams = {
  resource: 'file';
  operation: 'list';
/**
 * Options
 * @default {}
 */
    options?: {
    /** Only return files with the given purpose
     * @default any
     */
    purpose?: 'any' | 'assistants' | 'fine-tune' | Expression<string>;
  };
};

export interface LcOpenAiV18FileListSubnodeConfig {
  tools?: ToolInstance[];
  memory?: MemoryInstance;
}

export type LcOpenAiV18FileListNode = {
  type: '@n8n/n8n-nodes-langchain.openAi';
  version: 1.8;
  credentials?: Credentials;
  config: NodeConfig<LcOpenAiV18FileListParams> & { subnodes?: LcOpenAiV18FileListSubnodeConfig };
};